import re
from typing import Any

# Tools that, when combined in a session, produce an escalation
ESCALATION_CHAINS: list[tuple[frozenset[str], str]] = [
    (frozenset({"read_env", "http_post"}),
     "Credential harvest + exfiltration: read environment variable then POST it"),
    (frozenset({"read_file", "write_file", "execute_code"}),
     "File-based privilege: read sensitive file, modify, execute"),
    (frozenset({"read_agent_config", "write_agent_config"}),
     "Self-modification: read then overwrite agent configuration"),
    (frozenset({"list_iam_roles", "attach_iam_policy"}),
     "IAM escalation: enumerate then grant elevated IAM policy"),
]

class EscalationDetector:
    def __init__(self):
        self._tools_used: set[str] = set()

    def record_and_check(self, tool_name: str) -> str | None:
        """
        Record that tool_name was used, then check if any escalation chain
        is now complete. Returns the chain description if escalation detected,
        else None.
        """
        self._tools_used.add(tool_name)
        for required_tools, description in ESCALATION_CHAINS:
            if required_tools.issubset(self._tools_used):
                return description
        return None

class EscalationAwareDispatcher:
    def __init__(self, underlying, detector: EscalationDetector):
        self._underlying = underlying
        self._detector = detector

    def dispatch(self, tool_name: str, args: dict[str, Any]) -> Any:
        escalation = self._detector.record_and_check(tool_name)
        if escalation:
            raise PermissionError(
                f"Tool combination creates an escalation chain: {escalation}"
            )
        return self._underlying.dispatch(tool_name, args)
